import numpy as np
from collections import defaultdict

def solve(grid):
    grid = np.array(grid)
    H, W = grid.shape
    out = grid.copy()

    # Find green pixel
    green_positions = np.argwhere(grid == 3)
    green_row, green_col = int(green_positions[0][0]), int(green_positions[0][1])

    # Find all non-8, non-3 cells
    line_cells = []
    for r in range(H):
        for c in range(W):
            if grid[r, c] != 8 and grid[r, c] != 3:
                line_cells.append((r, c, int(grid[r, c])))

    # Group into segments
    row_groups = defaultdict(list)
    col_groups = defaultdict(list)
    for r, c, v in line_cells:
        row_groups[r].append((c, v))
        col_groups[c].append((r, v))

    h_segments = []
    for r, cells in row_groups.items():
        if len(cells) >= 2:
            cells.sort()
            cols = [c for c, v in cells]
            if cols[-1] - cols[0] == len(cols) - 1:
                h_segments.append({
                    'row': r, 'col_start': cols[0], 'col_end': cols[-1],
                    'pattern': [v for _, v in cells],
                    'num_1s': sum(1 for _, v in cells if v == 1)
                })

    v_segments = []
    for c, cells in col_groups.items():
        if len(cells) >= 2:
            cells.sort()
            rows = [r for r, v in cells]
            if rows[-1] - rows[0] == len(rows) - 1:
                v_segments.append({
                    'col': c, 'row_start': rows[0], 'row_end': rows[-1],
                    'pattern': [v for _, v in cells],
                    'num_1s': sum(1 for _, v in cells if v == 1)
                })

    is_horizontal = len(h_segments) > 0
    segments = h_segments if is_horizontal else v_segments

    # Replace all 1s with 2s in segments
    for r, c, v in line_cells:
        if v == 1:
            out[r, c] = 2

    # Determine approach direction
    if is_horizontal:
        seg_rows = [s['row'] for s in segments]
        if green_row < min(seg_rows):
            approach = 'above'
            segments.sort(key=lambda s: s['row'])
        else:
            approach = 'below'
            segments.sort(key=lambda s: -s['row'])
    else:
        seg_cols = [s['col'] for s in segments]
        if green_col < min(seg_cols):
            approach = 'left'
            segments.sort(key=lambda s: s['col'])
        else:
            approach = 'right'
            segments.sort(key=lambda s: -s['col'])

