        pattern = seg['pattern']
        first, last = pattern[0], pattern[-1]
        if first == 1 and last != 1:
            return 'start'
        elif last == 1 and first != 1:
            return 'end'
        elif first == 1 and last == 1:
            if is_horizontal:
                pos_in_seg = current_perp_pos - seg['col_start']
            else:
                pos_in_seg = current_perp_pos - seg['row_start']
            left_1s = sum(1 for v in pattern[:pos_in_seg] if v == 1)
            right_1s = sum(1 for v in pattern[pos_in_seg+1:] if v == 1)
            if right_1s > left_1s:
                return 'end'
            elif left_1s > right_1s:
                return 'start'
            else:
                return 'start' if pos_in_seg <= len(pattern) // 2 else 'end'
        return 'start'

    green_cells = set()

