        cur_r, cur_c = green_row, green_col
        for seg in segments:
            offset = seg['num_1s'] + 1
            turn_r = seg['row'] - offset if approach == 'above' else seg['row'] + offset

            for r in range(min(cur_r, turn_r), max(cur_r, turn_r) + 1):
                green_cells.add((r, cur_c))

            one_end = determine_1_end(seg, cur_c)
            if one_end == 'start':
                wrap_c = seg['col_end'] + offset
            else:
                wrap_c = seg['col_start'] - offset

            for c in range(min(cur_c, wrap_c), max(cur_c, wrap_c) + 1):
                green_cells.add((turn_r, c))

            cur_r, cur_c = turn_r, wrap_c

        if approach == 'above':
            for r in range(cur_r, H):
                green_cells.add((r, cur_c))
        else:
            for r in range(0, cur_r + 1):
                green_cells.add((r, cur_c))
    else:
        cur_r, cur_c = green_row, green_col
        for seg in segments:
            offset = seg['num_1s'] + 1
            turn_c = seg['col'] - offset if approach == 'left' else seg['col'] + offset

            for c in range(min(cur_c, turn_c), max(cur_c, turn_c) + 1):
                green_cells.add((cur_r, c))

            one_end = determine_1_end(seg, cur_r)
            if one_end == 'start':
                wrap_r = seg['row_end'] + offset
            else:
                wrap_r = seg['row_start'] - offset

            for r in range(min(cur_r, wrap_r), max(cur_r, wrap_r) + 1):
                green_cells.add((r, turn_c))

            cur_r, cur_c = wrap_r, turn_c

        if approach == 'left':
            for c in range(cur_c, W):
                green_cells.add((cur_r, c))
        else:
            for c in range(0, cur_c + 1):
                green_cells.add((cur_r, c))

    for r, c in green_cells:
        out[r, c] = 3

    return out.tolist()

